/** UsptEvlSlctnObjcReqstDao.insert */
insert into uspt_evl_slctn_objc_reqst
	(
		evl_slctn_objc_reqst_id
		, evl_trget_id
		, objc_reqst_cn
		, objc_reqst_dt
		, objc_applcnt_id
		, last_slctn_objc_process_sttus_cd
		, dlbrt_de
		, dlbrt_cn
		, dlbrt_opetr_id
		, applcnt_attachment_group_id
		, dlbrt_attachment_group_id
		, reject_reason_cn
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{evlSlctnObjcReqstId}
		, #{evlTrgetId}
		, #{objcReqstCn}
		, #{objcReqstDt}
		, #{objcApplcntId}
		, #{lastSlctnObjcProcessSttusCd}
		, #{dlbrtDe}
		, #{dlbrtCn}
		, #{dlbrtOpetrId}
		, #{applcntAttachmentGroupId}
		, #{dlbrtAttachmentGroupId}
		, #{rejectReasonCn}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptEvlSlctnObjcReqstDao.update */
update uspt_evl_slctn_objc_reqst
set
	objc_reqst_cn		= #{objcReqstCn}
	, objc_reqst_dt		= #{objcReqstDt}
	, objc_applcnt_id	= #{objcApplcntId}
	, dlbrt_de			= #{dlbrtDe}
	, dlbrt_cn			= #{dlbrtCn}
	, dlbrt_opetr_id	= #{dlbrtOpetrId}
	, reject_reason_cn	= #{rejectReasonCn}
	, last_slctn_objc_process_sttus_cd	= #{lastSlctnObjcProcessSttusCd}
	, applcnt_attachment_group_id		= #{applcntAttachmentGroupId}
	, dlbrt_attachment_group_id			= #{dlbrtAttachmentGroupId}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
where
	evl_slctn_objc_reqst_id = #{evlSlctnObjcReqstId}

mapper.select:
/** UsptEvlSlctnObjcReqstDao.selectCountByTrgetId */
select
	count(evl_slctn_objc_reqst_id)
from uspt_evl_slctn_objc_reqst
where
	evl_trget_id = #{trgetId}

sql.where:
sor.objc_applcnt_id = #{memberId}

	and sor.objc_reqst_dt >= to_date(#{objcReqstStartDate}, 'yyyymmdd')


	and sor.objc_reqst_dt <= to_date(#{objcReqstEndDate}, 'yyyymmdd')


	and sor.last_slctn_objc_process_sttus_cd = #{lastSlctnObjcProcessSttusCd}




			and ubpat.task_nm_ko like concat('%', #{keyword}, '%')


			and ubp.pblanc_nm like concat('%', #{keyword}, '%')

mapper.select:
/** UsptEvlSlctnObjcReqstDao.selectFrontListCount */ select count(sub.objc_reqst_id) from ( select sor.evl_slctn_objc_reqst_id as objc_reqst_id from uspt_evl_slctn_objc_reqst sor inner join uspt_evl_trget uet on uet.evl_trget_id = sor.evl_trget_id inner join uspt_evl_step ues on ues.evl_step_id = uet.evl_step_id inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = uet.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id
union all select sor.last_slctn_objc_reqst_id as objc_reqst_id from uspt_last_slctn_objc_reqst sor inner join uspt_last_slctn_trget ulst on ulst.last_slctn_trget_id = sor.last_slctn_trget_id inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = ulst.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id
) sub

/** UsptEvlSlctnObjcReqstDao.selectFrontList */ select sub.* from ( select sor.evl_slctn_objc_reqst_id as objc_reqst_id , sor.objc_reqst_dt , sor.last_slctn_objc_process_sttus_cd , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@LSOPS_CODE_GROUP}', sor.last_slctn_objc_process_sttus_cd) as last_slctn_objc_process_sttus , ues.evl_step_nm , ubpat.task_nm_ko as task_nm , ubp.pblanc_nm from uspt_evl_slctn_objc_reqst sor inner join uspt_evl_trget uet on uet.evl_trget_id = sor.evl_trget_id inner join uspt_evl_step ues on ues.evl_step_id = uet.evl_step_id inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = uet.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id
union all select sor.last_slctn_objc_reqst_id as objc_reqst_id , sor.objc_reqst_dt , sor.last_slctn_objc_process_sttus_cd , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@LSOPS_CODE_GROUP}', sor.last_slctn_objc_process_sttus_cd) as last_slctn_objc_process_sttus , '최종선정' as evl_step_nm , ubpat.task_nm_ko as task_nm , ubp.pblanc_nm from uspt_last_slctn_objc_reqst sor inner join uspt_last_slctn_trget ulst on ulst.last_slctn_trget_id = sor.last_slctn_trget_id inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.apply_id = ulst.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpa.pblanc_id
) sub offset #{beginRowNum} -1 limit #{itemsPerPage}
